    rand lc_ctrl_regs_reg_claim_transition_if claim_transition_if;
    rand lc_ctrl_regs_reg_transition_regwen transition_regwen;
    rand lc_ctrl_regs_reg_transition_cmd transition_cmd;
    rand lc_ctrl_regs_reg_transition_ctrl transition_ctrl;
    rand lc_ctrl_regs_reg_transition_token transition_token[4];
    rand lc_ctrl_regs_reg_transition_target transition_target;
    rand lc_ctrl_regs_reg_otp_vendor_test_ctrl otp_vendor_test_ctrl;
    rand lc_ctrl_regs_reg_otp_vendor_test_status otp_vendor_test_status;
    rand lc_ctrl_regs_reg_lc_state lc_state;
