    rand lc_ctrl_regs_reg_hw_revision1 hw_revision1;
    rand lc_ctrl_regs_reg_device_id device_id[8];
    rand lc_ctrl_regs_reg_manuf_state manuf_state[8];

    `uvm_object_utils(lc_ctrl_regs_reg_block)

    function new(string name = "",
                 int    has_coverage = UVM_NO_COVERAGE);
      super.new(name, has_coverage);
    endfunction : new

    virtual function void build(uvm_reg_addr_t base_addr);
      // create default map
      this.default_map = create_map(.name("default_map"),
                                    .base_addr(base_addr),
                                    .n_bytes(4),
                                    .endian(UVM_LITTLE_ENDIAN));
      // create registers
      alert_test =
          (lc_ctrl_regs_reg_alert_test::
           type_id::create("alert_test"));
      alert_test.configure(.blk_parent(this));
      alert_test.build();
      default_map.add_reg(.rg(alert_test),
                          .offset(32'h0));
      status =
          (lc_ctrl_regs_reg_status::
           type_id::create("status"));
      status.configure(.blk_parent(this));
      status.build();
      default_map.add_reg(.rg(status),
                          .offset(32'h4));
           
      claim_transition_if_regwen =
          (lc_ctrl_regs_reg_claim_transition_if_regwen::
           type_id::create("claim_transition_if_regwen"));
      claim_transition_if_regwen.configure(.blk_parent(this));
