           type_id::create("status"));
      status.configure(.blk_parent(this));
      status.build();
      default_map.add_reg(.rg(status),
                          .offset(32'h14));
           
      configopts =
          (spi_host_reg_configopts::
           type_id::create("configopts"));
      configopts.configure(.blk_parent(this));
      configopts.build();
      default_map.add_reg(.rg(configopts),
